-- ==========================================
-- 003_seed_data.sql
-- Expanded production seed data for RK Coaching LMS
-- ==========================================

-- 1. Clean legacy classes
DELETE FROM public.classes WHERE id NOT IN ('c6', 'c7', 'c8', 'c9', 'c10', 'c11s', 'c12s', 'neet', 'bpharma', 'nursing');

-- 2. Seed Academic Standards (Classes)
ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, slug = EXCLUDED.slug, priority = EXCLUDED.priority;

-- 3. Seed Subjects
ON CONFLICT (id) DO UPDATE SET "classId" = EXCLUDED."classId", name = EXCLUDED.name, icon = EXCLUDED.icon, description = EXCLUDED.description;

-- 4. Seed Courses
ON CONFLICT (id) DO UPDATE SET "classId" = EXCLUDED."classId", "subjectId" = EXCLUDED."subjectId", title = EXCLUDED.title, subtitle = EXCLUDED.subtitle, description = EXCLUDED.description, "thumbnailUrl" = EXCLUDED."thumbnailUrl", "isPremium" = EXCLUDED."isPremium", price = EXCLUDED.price, "discountPrice" = EXCLUDED."discountPrice";

-- 5. Seed Chapters
ON CONFLICT (id) DO UPDATE SET "subjectId" = EXCLUDED."subjectId", name = EXCLUDED.name, description = EXCLUDED.description, "orderIndex" = EXCLUDED."orderIndex";

-- 6. Seed Lessons
ON CONFLICT (id) DO UPDATE SET "chapterId" = EXCLUDED."chapterId", "courseId" = EXCLUDED."courseId", title = EXCLUDED.title, description = EXCLUDED.description, "orderIndex" = EXCLUDED."orderIndex", "isPremium" = EXCLUDED."isPremium";

-- 7. Seed Videos
ON CONFLICT (id) DO UPDATE SET "lessonId" = EXCLUDED."lessonId", title = EXCLUDED.title, provider = EXCLUDED.provider, "videoIdOrUrl" = EXCLUDED."videoIdOrUrl", "durationSeconds" = EXCLUDED."durationSeconds";

-- 8. Seed Notes
ON CONFLICT (id) DO UPDATE SET "lessonId" = EXCLUDED."lessonId", "classId" = EXCLUDED."classId", "subjectId" = EXCLUDED."subjectId", type = EXCLUDED.type, title = EXCLUDED.title, "pdfUrl" = EXCLUDED."pdfUrl", "sizeBytes" = EXCLUDED."sizeBytes", "isPremium" = EXCLUDED."isPremium", price = EXCLUDED.price;
